import{_ as o,I as e,c,a as s,b as d,w as l,d as i,r as n,o as p}from"./index-fb391eaf.js";const r="/assets/ches3-423fef86.jpg",v="/assets/strelka3-27b6f1bb.jpg",b="/assets/chess_160-dbd4f3a3.jpg";const _={components:{ImgComparisonSlider:e}},m={class:"container"},f={class:"section"},x={class:"forimg full"};function g(u,a,C,h,k,w){const t=n("ImgComparisonSlider");return p(),c("div",m,[a[2]||(a[2]=s("h2",null,"Всё PRO чеснок",-1)),a[3]||(a[3]=s("div",{class:"section"},[s("p",{class:"text"},"Чеснок - одна из самых популярных и востребованных приправ на свете: практически любое блюдо сопровождается использованием чеснока. В каждом доме едят чеснок как сырым, так и в блюдах. В чем же заключается такая популярность?")],-1)),s("div",f,[s("div",x,[d(t,null,{default:l(()=>[...a[0]||(a[0]=[s("img",{slot:"first",style:{width:"100%"},src:r},null,-1),s("img",{slot:"second",style:{width:"100%"},src:v},null,-1)])]),_:1})]),a[1]||(a[1]=s("div",{class:"fortext"},[s("p",{class:"text"},"Чеснок - древнейшее культурное растение, которое возделывается со времен неолита. Главное преимущество использования чеснока в пищу заключается в его бактерицидном действии, убивая болезнетворные бактерии как в сыром виде, так и термически обработанном. "),s("p",{class:"text"},"Луковицы чеснока содержат эфирные масла, гликозид аллин, витамины группы В и С, магний, кальций, фосфор, йод, хлор и множество других микроэлементов. Чеснок нормализует обмен веществ, понижает давление, помогает выведению холестерина")],-1))]),a[4]||(a[4]=i('<div class="section" data-v-c1b3134a><div class="fortext" data-v-c1b3134a><p class="text" data-v-c1b3134a>Сегодня существует около 300 разновидностей чеснока.</p><p class="text" data-v-c1b3134a> Для выращивания на нашем хозяйстве были выбраны несколько сортов чеснока, таких как «ЛЮБАША», «ДОБРЫНЯ», «БОГАТЫРЬ».</p></div><div class="forimg w-40" data-v-c1b3134a><img src="'+b+'" data-v-c1b3134a></div></div><h2 data-v-c1b3134a>Преимущества сортового чеснока</h2><div class="section" data-v-c1b3134a><ol data-v-c1b3134a><li data-v-c1b3134a><p class="text" data-v-c1b3134a>Данные сорта отличается отличными морозостойкими характеристиками, которые выдерживают понижение температуры до -38°C, так как являются озимыми;</p></li><li data-v-c1b3134a><p class="text" data-v-c1b3134a>Созревшие луковицы ВЫСШЕГО СОРТА отличаются большими размерами 100-140г;</p></li><li data-v-c1b3134a><p class="text" data-v-c1b3134a>Луковица состоит из 6-8 зубчиков;</p></li><li data-v-c1b3134a><p class="text" data-v-c1b3134a>Чеснок с острым перечным привкусом, что превосходно подходит для кулинарии;</p></li><li data-v-c1b3134a><p class="text" data-v-c1b3134a>Чеснок отличается высокой длительностью хранения. При соблюдении правил хранения, чеснок будет радовать вас своими вкусовыми качествами на протяжении 12 месяцев. Для этого необходимо исключить сквозняки и попадание влаги. При обеспечении температуры хранения -2°С наш чеснок может храниться до 3 лет. При такой температуре чеснок впадает в состояние анабиоза, в нем замедляются процессы роста. Но, как только внешняя температура переступит 0°С, чеснок возобновит свой рост.</p></li></ol></div><h4 data-v-c1b3134a>2025©</h4><br data-v-c1b3134a>',5))])}const y=o(_,[["render",g],["__scopeId","data-v-c1b3134a"]]);export{y as default};
